const UMBRAL_TEMP = 28.0;
const UMBRAL_GAS = 3600;
const CICLOS_NORMAL = 100;
const CICLOS_ALERTA = 50;
const CICLOS_EMERGENCIA = 20;

const p = (typeof msg.payload === "object" && msg.payload !== null) ? msg.payload : {};

function toNumber(v) {
    if (v === null || v === undefined || v === "") return NaN;
    const n = Number(v);
    return Number.isFinite(n) ? n : NaN;
}

const temperatura = toNumber(p.temperatura_C ?? p.temperatura ?? p.temp);
const gas = toNumber(p.mq135_aire ?? p.gas ?? p.mq135);

let estado = "";
let ciclos = 0;
let detalle = "";

if (Number.isFinite(temperatura) && Number.isFinite(gas)) {
    if (temperatura >= UMBRAL_TEMP && gas >= UMBRAL_GAS) {
        estado = "EMERGENCIA";
        ciclos = CICLOS_EMERGENCIA;
        detalle = "Temperatura y gas altos";
    } else if (temperatura >= UMBRAL_TEMP || gas >= UMBRAL_GAS) {
        estado = "ALERTA";
        ciclos = CICLOS_ALERTA;
        detalle = "Temperatura o gas alto";
    } else {
        estado = "NORMAL";
        ciclos = CICLOS_NORMAL;
        detalle = "Valores dentro de rango";
    }
} else {
    estado = String(p.estado_riesgo || "INVALIDO").toUpperCase();
    detalle = "No llegaron temperatura_C y mq135_aire; se conserva estado recibido";
}

msg.payload.temperatura_C = Number.isFinite(temperatura) ? temperatura : p.temperatura_C;
msg.payload.mq135_aire = Number.isFinite(gas) ? gas : p.mq135_aire;
msg.payload.estado_riesgo = estado;
msg.payload.procesado_nodered = true;
msg.payload.tiempo_espera_seg = ciclos > 0 ? ciclos * 0.1 : null;
msg.payload.detalle_estado = detalle;

if (estado === "NORMAL") {
    node.status({ fill: "green", shape: "dot", text: "NORMAL" });
} else if (estado === "ALERTA") {
    node.status({ fill: "yellow", shape: "dot", text: "ALERTA" });
} else if (estado === "EMERGENCIA") {
    node.status({ fill: "red", shape: "dot", text: "EMERGENCIA" });
} else {
    node.status({ fill: "grey", shape: "ring", text: estado });
}

const resumen = {
    topic: msg.topic,
    payload: {
        estado: estado,
        temperatura_C: msg.payload.temperatura_C,
        mq135_aire: msg.payload.mq135_aire,
        detalle: detalle,
        timestamp: msg.payload.timestamp || null
    }
};

return [msg, resumen];

const p = msg.payload || {};

const temp = Number(p.temperatura_C);
const gas = Number(p.mq135_aire);
if (!Number.isFinite(temp) || !Number.isFinite(gas)) {
    return null;
}

const deviceId = String(p.device_id || "ESP32");
const zona = String(p.zona || "N/A");
const estado = String(p.estado_riesgo || "INVALIDO");
let ts = String(p.timestamp || "");

if (!ts) {
    const now = new Date();
    ts = now.toISOString().slice(0, 19).replace("T", " ");
}

msg.topic = "INSERT INTO mediciones (device_id, zona, temperatura_c, mq135_aire, estado_riesgo, timestamp_origen) VALUES (?, ?, ?, ?, ?, ?)";
msg.payload = [deviceId, zona, Number(temp.toFixed(2)), Math.round(gas), estado, ts];
msg.queryType = "insert";

return msg;

const estado = String((msg.payload && msg.payload.estado_riesgo) || "").toUpperCase();

function indicador(nombre) {
    const activo = estado === nombre;
    return {
        payload: {
            estado: nombre,
            marca: activo ? "ACTIVO" : "INACTIVO",
            actual: estado
        }
    };
}

return [
    indicador("NORMAL"),
    indicador("ALERTA"),
    indicador("EMERGENCIA")
];

msg.topic = "DELETE FROM mediciones;";
msg.payload = [];
msg.queryType = "deleteAll";
return msg;

const estado = String(msg.payload || "").trim().toUpperCase();

const base = "SELECT id, device_id, zona, temperatura_c, mq135_aire, estado_riesgo, timestamp_origen, created_at FROM mediciones";

if (["NORMAL", "ALERTA", "EMERGENCIA"].includes(estado)) {
    msg.topic = `${base} WHERE estado_riesgo='${estado}' ORDER BY id DESC LIMIT 20;`;
} else {
    msg.topic = `${base} ORDER BY id DESC LIMIT 20;`;
}

msg.queryType = "select";
return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [];

if (rows.length === 0) {
    msg.payload = "Sin resultados";
    return msg;
}

const cols = ["id", "device_id", "zona", "temperatura_c", "mq135_aire", "estado_riesgo", "timestamp_origen"];
const safe = (v) => String(v ?? "");
const maxRows = 20;
const data = rows.slice(0, maxRows);

const widths = cols.map((c) => c.length);
for (const r of data) {
    cols.forEach((c, i) => {
        const l = safe(r[c]).length;
        if (l > widths[i]) widths[i] = Math.min(l, 28);
    });
}

const trunc = (s, w) => (s.length > w ? s.slice(0, w - 1) + "…" : s);
const pad = (s, w) => trunc(s, w).padEnd(w, " " );

const header = cols.map((c, i) => pad(c, widths[i])).join(" | " );
const sep = widths.map((w) => "-".repeat(w)).join("-+-");
const body = data.map((r) => cols.map((c, i) => pad(safe(r[c]), widths[i])).join(" | " )).join("\n");

msg.payload = `Filas devueltas: ${rows.length}\n\n${header}\n${sep}\n${body}`;
return msg;
